from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["god-mode-home-frontend"])

HTML = """
<!doctype html>
<html lang="pt-PT">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>God Mode Home</title>
  <style>
    :root{color-scheme:dark;--bg:#050816;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--accent:#38bdf8;--green:#22c55e;--warn:#f59e0b;--bad:#ef4444}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#123256,#050816 55%);color:var(--text)}.page{min-height:100vh;padding:10px;display:grid;gap:10px}.top,.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px;box-shadow:0 14px 34px rgba(0,0,0,.32)}h1,h2{margin:.1rem 0}.hero{font-size:28px;font-weight:1000;line-height:1.1}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:9px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:8px}button,input,textarea{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}button.stop{background:linear-gradient(135deg,#991b1b,#ef4444);color:white}.chat{display:grid;gap:8px;max-height:44vh;overflow:auto}.msg{padding:10px;border-radius:18px;border:1px solid var(--line);background:#0b1220;white-space:pre-wrap}.operator{margin-left:20px;background:#111827}.assistant{margin-right:20px;background:#0f1b35}.light{display:inline-flex;border-radius:999px;padding:7px 10px;font-weight:900}.green{background:#052e16;color:#86efac}.yellow{background:#422006;color:#fde68a}.blue{background:#082f49;color:#7dd3fc}.red{background:#450a0a;color:#fecaca}.easybox{display:grid;gap:10px}.easyhead{font-size:20px;font-weight:1000}.command{display:grid;gap:6px;text-align:left}.command small{color:var(--muted);font-weight:600}.resultCard{border:1px solid var(--line);border-radius:20px;background:#081226;padding:12px;display:grid;gap:8px}.resultTitle{font-size:19px;font-weight:1000}.resultOk{color:#86efac}.resultWarn{color:#fde68a}.resultBad{color:#fecaca}.pill{display:inline-flex;border:1px solid var(--line);border-radius:999px;padding:5px 9px;color:var(--muted);font-size:12px}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:320px}@media(max-width:760px){.hero{font-size:23px}.buttons{grid-template-columns:1fr}.page{padding:8px}}
  </style>
</head>
<body>
<div class="page">
  <section class="top"><h1>God Mode</h1><p class="muted">Home principal. Chat, autopilot, aprovações e prioridade do operador num só sítio.</p><div class="hero" id="hero">A carregar...</div><div id="light"></div></section>
  <section class="panel buttons"><button id="continue">Continuar</button><button id="easy" class="dark">Modo fácil</button><button id="artifacts" class="dark">APK/EXE</button><button id="install" class="dark">Instalar/1º arranque</button><button id="start">Ligar PC Autopilot</button><button id="stop" class="stop">Parar</button><button id="ready" class="dark">Pronto para usar</button><button id="approve" class="dark">Aprovar próximo</button><button onclick="location.href='/app/operator-chat-sync-cards'" class="dark">Chat completo</button><button onclick="location.href='/app/mobile-approval-cockpit-v2'" class="dark">Problemas/OK</button></section>
  <section class="grid" id="summary"></section>
  <section class="panel" id="easyPanel" style="display:none"><h2>Modo fácil</h2><div class="easybox" id="easyContent"></div><div class="easybox" id="easyResult"></div></section>
  <section class="panel"><h2>Chat rápido</h2><div class="chat" id="chat"></div><textarea id="msg" rows="3" placeholder="Dá uma ordem: continua o projeto, revê problemas, cria próxima fase..."></textarea><input id="project" placeholder="Projeto opcional, ex: GOD_MODE, PROVENTIL"><div class="buttons"><button id="send">Enviar e executar</button><button id="refresh" class="dark">Atualizar</button><button id="driving" class="dark">Modo condução</button></div></section>
  <section class="panel"><h2>Ações principais</h2><div class="buttons" id="actions"></div></section>
  <section class="panel"><h2>Último resultado</h2><pre id="out"></pre></section>
</div>
<script>
let state={};const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(v){return String(v??'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;')}function show(v){qs('#out').textContent=JSON.stringify(v,null,2)}function card(a,b,c=''){return `<div class="card"><span class="muted">${esc(a)}</span><b style="font-size:23px;display:block">${esc(b)}</b><span class="muted">${esc(c)}</span></div>`}function addMsg(role,text){const box=document.createElement('div');box.className='msg '+(role==='operator'?'operator':'assistant');box.textContent=text;qs('#chat').appendChild(box);qs('#chat').scrollTop=qs('#chat').scrollHeight}async function post(path,body={}){const r=await api(path,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});show(r);await load();return r}function renderResultCard(r){const report=r?.result?.report||{};const result=r?.result||{};const operatorNext=r?.operator_next||{};const ok=r?.ok===true;const title=ok?'Ação enviada':'Ação com problema';const cls=ok?'resultOk':'resultBad';const job=report.job_id||result.job_id||r?.flow?.route_result?.job_id||'—';const project=report.resolved_project_id||r?.project||r?.requested_project||state.active_project||'—';const stop=report.autopilot_stop_reason||r?.flow?.route_result?.autopilot_stop_reason||'—';const score=result.health_score??result.readiness_score??r?.score??'—';const steps=Array.isArray(result.steps)?result.steps.length:null;const artifacts=result.artifact_count??r?.flow?.artifacts_status?.artifact_count??null;const status=r?.status||result.status||'—';let extra='';if(steps!==null){extra+=`<span class="pill">Passos: ${esc(steps)}</span>`}if(artifacts!==null){extra+=`<span class="pill">APK/EXE: ${esc(artifacts)}</span>`}if(score!=='—'){extra+=`<span class="pill">Score: ${esc(score)}</span>`}if(status!=='—'){extra+=`<span class="pill">Estado: ${esc(status)}</span>`}qs('#easyResult').innerHTML=`<div class="resultCard"><div class="resultTitle ${cls}">${esc(title)}</div><div><span class="pill">Comando: ${esc(r?.command_id||r?.mode||'—')}</span> <span class="pill">Projeto: ${esc(project)}</span> <span class="pill">Job: ${esc(job)}</span> <span class="pill">Stop: ${esc(stop)}</span> ${extra}</div><div class="muted">Próxima ação: ${esc(operatorNext.label||'Voltar à Home')}</div><div class="buttons">${operatorNext.route?`<button class="dark" onclick="location.href='${esc(operatorNext.route)}'">Abrir próxima ação</button>`:''}<button class="dark" onclick="show(window.__lastEasyResult||{})">Ver JSON</button></div></div>`}async function runPayloadButton(endpoint,payload={}){qs('#easyResult').innerHTML='<div class="resultCard"><div class="resultTitle resultWarn">A executar...</div><div class="muted">O backend está a correr o teste/ação.</div></div>';const project=qs('#project').value.trim()||state.active_project||'GOD_MODE';const body={...payload};if(!body.tenant_id){body.tenant_id='owner-andre'}if(!body.requested_project){body.requested_project=project}const r=await api(endpoint,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});window.__lastEasyResult=r;show(r);renderResultCard(r);await load();return r}async function routeCommand(commandId,route_endpoint='/api/daily-command-router/route'){/* routeCommand(commandId) */const project=qs('#project').value.trim()||state.active_project||null;qs('#easyResult').innerHTML='<div class="resultCard"><div class="resultTitle resultWarn">A executar...</div><div class="muted">O backend está a encaminhar o comando.</div></div>';const r=await api(route_endpoint,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({command_id:commandId,tenant_id:'owner-andre',requested_project:project})});window.__lastEasyResult=r;show(r);renderResultCard(r);if(r.message){addMsg('operator',r.message)}const report=r.result?.report;if(report){addMsg('assistant',`Job: ${report.job_id||'—'}\nProjeto: ${report.resolved_project_id||r.project||'—'}\nStop: ${report.autopilot_stop_reason||'—'}`)}await load();return r}function renderEasy(panel){qs('#easyPanel').style.display='block';const commands=(panel.quick_commands||[]).map(c=>`<button class="command" onclick="routeCommand('${esc(c.id)}','${esc(c.route_endpoint||panel.daily_command_route_endpoint||'/api/daily-command-router/route')}')"><b>${esc(c.label)}</b><small>${esc(c.message)}</small></button>`).join('');const safe=(panel.safe_buttons||[]).map((b,i)=>{window.__easyPayloads=window.__easyPayloads||{};const key='safe_'+i;window.__easyPayloads[key]=b.payload||{};return b.payload?.command_id?`<button class="dark" onclick="routeCommand('${esc(b.payload.command_id)}','${esc(b.endpoint||panel.daily_command_route_endpoint||'/api/daily-command-router/route')}')">${esc(b.label)}</button>`:b.payload?`<button class="dark" onclick="runPayloadButton('${esc(b.endpoint)}',window.__easyPayloads['${key}'])">${esc(b.label)}</button>`:b.route?`<button class="dark" onclick="location.href='${esc(b.route)}'">${esc(b.label)}</button>`:b.endpoint?`<button class="dark" onclick="post('${esc(b.endpoint)}',{})">${esc(b.label)}</button>`:''}).join('');qs('#easyContent').innerHTML=`<div class="easyhead">${esc(panel.headline||'Modo fácil')}</div><div class="muted">Projeto ativo: ${esc(panel.active_project||'—')}</div><div class="buttons">${safe}</div><h3>Comandos rápidos</h3><div class="buttons">${commands}</div><div class="muted">${(panel.operator_rules||[]).map(esc).join('<br>')}</div>`}function render(d){state=d;const l=d.traffic_light||{};const ready=d.ready_to_use||{};const install=d.install_first_run||{};const artifacts=d.artifacts_center||{};qs('#hero').textContent=d.operator_message||((l.label||'Pronto')+' · '+(d.next_task?.label||''));qs('#light').innerHTML=`<span class="light ${esc(l.color||'blue')}">${esc(l.label||'Pronto')}</span>`;qs('#summary').innerHTML=card('Projeto ativo',d.active_project||'—')+card('Pronto para usar',(ready.readiness_score??0)+'%',ready.status||'—')+card('Instalação',(install.done_count??0)+' passos',install.status||'—')+card('APK/EXE',artifacts.artifact_count??0,artifacts.status||'—')+card('PC Autopilot',d.pc_autopilot?.status||'—')+card('Aprovações',d.approvals?.count||0)+card('Próxima tarefa',d.next_task?.label||'—');qs('#actions').innerHTML=(d.quick_actions||[]).map(a=>a.route?`<button class="dark" onclick="location.href='${esc(a.route)}'">${esc(a.label)}</button>`:`<button data-endpoint="${esc(a.endpoint)}">${esc(a.label)}</button>`).join('');qs('#actions').querySelectorAll('button[data-endpoint]').forEach(b=>b.onclick=()=>post(b.dataset.endpoint,{}));show(d)}async function load(){render(await api('/api/god-mode-home/dashboard'))}qs('#continue').onclick=()=>post('/api/god-mode-home/continue',{command_text:null,requested_project:qs('#project').value.trim()||null});qs('#easy').onclick=async()=>{const p=await api('/api/home-operator-ux/panel');renderEasy(p);show(p)};qs('#artifacts').onclick=async()=>show(await api('/api/artifacts-center/dashboard'));qs('#install').onclick=async()=>show(await api('/api/install-first-run/guide'));qs('#start').onclick=()=>post('/api/god-mode-home/start-autopilot');qs('#stop').onclick=()=>post('/api/god-mode-home/stop-autopilot');qs('#ready').onclick=async()=>show(await api('/api/ready-to-use/checklist'));qs('#approve').onclick=()=>post('/api/god-mode-home/approve-next',{});qs('#refresh').onclick=load;qs('#driving').onclick=async()=>show(await api('/api/god-mode-home/driving-mode'));qs('#send').onclick=async()=>{const text=qs('#msg').value.trim();if(!text)return;qs('#msg').value='';addMsg('operator',text);const r=await post('/api/god-mode-home/chat',{message:text,requested_project:qs('#project').value.trim()||null});const rep=r.result?.report;addMsg('assistant',rep?`Projeto: ${rep.resolved_project_id}\nJob: ${rep.job_id}\nStop: ${rep.autopilot_stop_reason||'—'}`:'Ordem enviada.');};qs('#msg').addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();qs('#send').click()}});load();
</script>
</body></html>
"""


@router.get('/app/god-mode-home', response_class=HTMLResponse)
async def god_mode_home_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/home', response_class=HTMLResponse)
async def god_mode_home_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/god-mode', response_class=HTMLResponse)
async def god_mode_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
